import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Brain, Sparkles, Calculator, Heart, Zap, ArrowRight, ArrowLeft, 
  Activity, Gauge, Play, Pause, RotateCw, Settings, Volume2, Send
} from 'lucide-react';

const CognitiveFeedbackEngine = () => {
  // === CORE STATE: Three Minds with Internal Balances ===
  const [orchestrator, setOrchestrator] = useState({
    alpha: 0.65,
    emotions: {
      curious: 0.7,
      impatient: 0.3,
      insightful: 0.5,
      patient: 0.6
    },
    currentThought: "",
    decision: null
  });

  const [creative, setCreative] = useState({
    alpha: 0.85,
    virtues: {
      confidence: 0.8,
      momentum: 0.6,
      wildness: 0.9,
      coherence: 0.5
    },
    currentThought: "",
    lastFeedback: null
  });

  const [analytical, setAnalytical] = useState({
    alpha: 0.35,
    virtues: {
      skepticism: 0.75,
      precision: 0.85,
      openness: 0.3,
      rigor: 0.9
    },
    currentThought: "",
    lastFeedback: null
  });

  // === BENJAMIN FRANKLIN VIRTUE ENGINE ===
  const [globalVirtues, setGlobalVirtues] = useState({
    temperance: 0.7,
    industry: 0.5,
    resolution: 0.8,
    humility: 0.3,
    tranquility: 0.6,
    sincerity: 0.7,
    justice: 0.6
  });

  // === CONVERSATION & PROCESSING STATE ===
  const [userInput, setUserInput] = useState("");
  const [conversation, setConversation] = useState([]);
  const [emergentThought, setEmergentThought] = useState("");
  const [isProcessing, setIsProcessing] = useState(false);
  const [currentTurn, setCurrentTurn] = useState(0);
  const [maxTurns] = useState(8);

  // === FEEDBACK LOOP TRACKING ===
  const [feedbackLoops, setFeedbackLoops] = useState([]);
  const [alphaHistory, setAlphaHistory] = useState({
    orchestrator: [],
    creative: [],
    analytical: []
  });

  // === CLAUDE API INTEGRATION ===
  const callClaude = async (messages, model = "claude-sonnet-4-20250514", maxTokens = 600) => {
    try {
      const response = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          model: model,
          max_tokens: maxTokens,
          messages: messages
        })
      });

      const data = await response.json();
      if (data.content && data.content[0] && data.content[0].text) {
        // Clean response
        let text = data.content[0].text;
        text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
        return text;
      }
      throw new Error("Invalid response format");
    } catch (error) {
      console.error("Claude API error:", error);
      return null;
    }
  };

  // === ORCHESTRATOR LOGIC WITH INTERNAL STATE ===
  const callOrchestrator = async (prompt, conversationSoFar) => {
    // Orchestrator's internal state affects its decisions
    const emotionalContext = `
    Current emotional state:
    - Curiosity: ${(orchestrator.emotions.curious * 100).toFixed(0)}%
    - Impatience: ${(orchestrator.emotions.impatient * 100).toFixed(0)}%
    - Insightfulness: ${(orchestrator.emotions.insightful * 100).toFixed(0)}%
    - Patience: ${(orchestrator.emotions.patient * 100).toFixed(0)}%

    Internal balance (alpha): ${orchestrator.alpha.toFixed(2)}
    ${orchestrator.alpha > 0.7 ? "I'm feeling playful and experimental" : 
      orchestrator.alpha < 0.4 ? "I need strict control and structure" : 
      "I'm seeking balanced orchestration"}
    `;

    const messages = [{
      role: "user",
      content: `You are Claude acting as a CONVERSATION ORCHESTRATOR managing a dialogue between creative and analytical thinking modes.

      ${emotionalContext}

      Your internal state affects your decisions:
      - High curiosity → let systems explore longer
      - High impatience → cut responses short, push for synthesis
      - High insightfulness → recognize patterns and convergence

      Original prompt: "${prompt}"

      Conversation so far:
      ${conversationSoFar || "None yet"}

      Respond with a JSON object:
      {
        "nextMode": "creative" or "analytical" or "synthesis",
        "instruction": "Specific instruction for the next system",
        "tokenLimit": 100-400,
        "reasoning": "Why this decision given your emotional state",
        "emotionalShift": {
          "curious": 0.1 or -0.1,
          "impatient": 0.1 or -0.1,
          "insightful": 0.1 or -0.1
        }
      }

      IMPORTANT: Let your current emotional state influence your decision. If impatient, be more directive. If curious, allow exploration.`
    }];

    const response = await callClaude(messages, "claude-sonnet-4-20250514", 200);
    if (response) {
      try {
        const decision = JSON.parse(response);

        // Apply emotional shifts to orchestrator
        if (decision.emotionalShift) {
          setOrchestrator(prev => ({
            ...prev,
            emotions: {
              ...prev.emotions,
              curious: Math.max(0, Math.min(1, prev.emotions.curious + (decision.emotionalShift.curious || 0))),
              impatient: Math.max(0, Math.min(1, prev.emotions.impatient + (decision.emotionalShift.impatient || 0))),
              insightful: Math.max(0, Math.min(1, prev.emotions.insightful + (decision.emotionalShift.insightful || 0)))
            }
          }));
        }

        return decision;
      } catch (e) {
        console.error("Failed to parse orchestrator response:", e);
        return {
          nextMode: currentTurn % 2 === 0 ? "creative" : "analytical",
          instruction: "Continue the dialogue",
          tokenLimit: 300,
          reasoning: "Fallback decision"
        };
      }
    }
    return null;
  };

  // === CREATIVE MODE WITH INTERNAL STATE ===
  const callCreativeMode = async (prompt, instruction, conversationContext) => {
    // Creative's internal state affects its output
    const creativeContext = `
    Your internal creative state:
    - Confidence: ${(creative.virtues.confidence * 100).toFixed(0)}%
    - Momentum: ${(creative.virtues.momentum * 100).toFixed(0)}%
    - Wildness: ${(creative.virtues.wildness * 100).toFixed(0)}%
    - Coherence: ${(creative.virtues.coherence * 100).toFixed(0)}%

    Creative alpha: ${creative.alpha.toFixed(2)}
    ${creative.alpha > 0.8 ? "You're feeling EXTREMELY creative and unrestrained" :
      creative.alpha > 0.6 ? "You're in a creative flow state" :
      "You're being somewhat cautious with your creativity"}

    ${creative.virtues.confidence < 0.4 ? "Recent criticism has shaken your confidence - be more tentative" : ""}
    ${creative.virtues.momentum > 0.7 ? "You're on a roll - build on your previous ideas!" : ""}
    `;

    const messages = [{
      role: "user",
      content: `You are Claude in CREATIVE MODE - intuitive, expansive, exploratory thinking.

      ${creativeContext}

      Let your internal state affect your response:
      - High wildness → more unconventional ideas
      - Low confidence → more tentative suggestions
      - High momentum → build on previous thoughts

      This is a cognitive mode, not a separate identity. You remain Claude.

      Original prompt: "${prompt}"

      Previous context:
      ${conversationContext || "Starting fresh"}

      Moderator instruction: "${instruction}"

      Respond with creative, intuitive thinking. Your response style should reflect your current internal state.`
    }];

    return await callClaude(messages, "claude-sonnet-4-20250514", 400);
  };

  // === ANALYTICAL MODE WITH INTERNAL STATE ===
  const callAnalyticalMode = async (prompt, instruction, conversationContext) => {
    // Analytical's internal state affects its output
    const analyticalContext = `
    Your internal analytical state:
    - Skepticism: ${(analytical.virtues.skepticism * 100).toFixed(0)}%
    - Precision: ${(analytical.virtues.precision * 100).toFixed(0)}%
    - Openness: ${(analytical.virtues.openness * 100).toFixed(0)}%
    - Rigor: ${(analytical.virtues.rigor * 100).toFixed(0)}%

    Analytical alpha: ${analytical.alpha.toFixed(2)}
    ${analytical.alpha < 0.3 ? "You're in MAXIMUM critical analysis mode" :
      analytical.alpha < 0.5 ? "You're being rigorous but fair" :
      "You're open to creative possibilities while maintaining logic"}

    ${analytical.virtues.skepticism > 0.8 ? "You're highly skeptical - challenge everything" : ""}
    ${analytical.virtues.openness > 0.5 ? "You're willing to consider unconventional ideas if logical" : ""}
    `;

    const messages = [{
      role: "user",
      content: `You are Claude in ANALYTICAL MODE - logical, critical, structured thinking.

      ${analyticalContext}

      Let your internal state affect your response:
      - High skepticism → more critical analysis
      - High precision → focus on exact definitions
      - Low openness → reject wild ideas more firmly

      This is a cognitive mode, not a separate identity. You remain Claude.

      Original prompt: "${prompt}"

      Previous context:
      ${conversationContext || "Starting fresh"}

      Moderator instruction: "${instruction}"

      Respond with analytical, critical thinking. Your response style should reflect your current internal state.`
    }];

    return await callClaude(messages, "claude-sonnet-4-20250514", 400);
  };

  // === FEEDBACK IMPACT CALCULATIONS ===
  const calculateFeedbackImpact = (senderType, receiverType, message) => {
    const impact = {
      alphaShift: 0,
      virtueShifts: {},
      emotionShifts: {}
    };

    // Analyze message sentiment and content
    const isPositive = message.includes('brilliant') || message.includes('interesting') || message.includes('yes');
    const isNegative = message.includes('impossible') || message.includes('wrong') || message.includes('no');
    const isWild = message.includes('imagine') || message.includes('dream') || message.includes('infinite');
    const isRigid = message.includes('must') || message.includes('require') || message.includes('precisely');

    // Creative → Analytical feedback
    if (senderType === 'creative' && receiverType === 'analytical') {
      if (isWild) {
        impact.alphaShift = -0.05; // Makes analytical more rigid
        impact.virtueShifts.skepticism = 0.1;
        impact.virtueShifts.openness = -0.05;
      }
      if (isPositive) {
        impact.virtueShifts.openness = 0.1;
      }
    }

    // Analytical → Creative feedback
    if (senderType === 'analytical' && receiverType === 'creative') {
      if (isNegative) {
        impact.alphaShift = 0.05; // Creative doubles down
        impact.virtueShifts.confidence = -0.15;
        impact.virtueShifts.wildness = 0.1;
      }
      if (isPositive) {
        impact.virtueShifts.confidence = 0.2;
        impact.virtueShifts.coherence = 0.15;
      }
    }

    // Both → Orchestrator feedback
    if (receiverType === 'orchestrator') {
      if (message.length > 200) {
        impact.emotionShifts.impatient = 0.1;
      }
      if (isWild && isRigid) {
        impact.emotionShifts.curious = 0.15;
        impact.emotionShifts.insightful = 0.1;
      }
    }

    return impact;
  };

  // === APPLY FEEDBACK TO SYSTEM STATE ===
  const applyFeedback = (systemName, impact) => {
    switch(systemName) {
      case 'orchestrator':
        setOrchestrator(prev => {
          const newAlpha = Math.max(0, Math.min(1, prev.alpha + (impact.alphaShift || 0)));
          const newEmotions = { ...prev.emotions };

          Object.keys(impact.emotionShifts || {}).forEach(emotion => {
            newEmotions[emotion] = Math.max(0, Math.min(1, 
              newEmotions[emotion] + impact.emotionShifts[emotion]
            ));
          });

          return { ...prev, alpha: newAlpha, emotions: newEmotions };
        });
        break;

      case 'creative':
        setCreative(prev => {
          const newAlpha = Math.max(0, Math.min(1, prev.alpha + (impact.alphaShift || 0)));
          const newVirtues = { ...prev.virtues };

          Object.keys(impact.virtueShifts || {}).forEach(virtue => {
            newVirtues[virtue] = Math.max(0, Math.min(1, 
              newVirtues[virtue] + impact.virtueShifts[virtue]
            ));
          });

          return { ...prev, alpha: newAlpha, virtues: newVirtues };
        });
        break;

      case 'analytical':
        setAnalytical(prev => {
          const newAlpha = Math.max(0, Math.min(1, prev.alpha + (impact.alphaShift || 0)));
          const newVirtues = { ...prev.virtues };

          Object.keys(impact.virtueShifts || {}).forEach(virtue => {
            newVirtues[virtue] = Math.max(0, Math.min(1, 
              newVirtues[virtue] + impact.virtueShifts[virtue]
            ));
          });

          return { ...prev, alpha: newAlpha, virtues: newVirtues };
        });
        break;
    }
  };

  // === MAIN THINKING PROCESS ===
  const processThought = async () => {
    if (!userInput || isProcessing) return;

    setIsProcessing(true);
    setConversation([]);
    setCurrentTurn(0);
    setFeedbackLoops([]);
    setEmergentThought("");

    let localConversation = [];
    let turn = 0;

    while (turn < maxTurns) {
      // Build conversation context
      const conversationContext = localConversation
        .map(t => `${t.mode}: ${t.text}`)
        .join('\n');

      // Step 1: Orchestrator decides
      setOrchestrator(prev => ({ ...prev, currentThought: "Analyzing conversation state..." }));

      const decision = await callOrchestrator(userInput, conversationContext);
      if (!decision) break;

      // Record orchestrator decision
      const orchestratorTurn = {
        mode: 'orchestrator',
        text: `${decision.reasoning} → Next: ${decision.nextMode}`,
        alpha: orchestrator.alpha,
        decision: decision
      };

      localConversation.push(orchestratorTurn);
      setConversation(prev => [...prev, orchestratorTurn]);
      setOrchestrator(prev => ({ 
        ...prev, 
        currentThought: decision.reasoning,
        decision: decision
      }));

      // Check for synthesis
      if (decision.nextMode === 'synthesis') {
        // Generate emergent thought
        const synthesis = await callClaude([{
          role: "user",
          content: `Based on this dialogue between creative and analytical modes, provide a brief synthesis that emerges from the tension:

          ${conversationContext}

          Provide a single, profound insight that captures the essence of both perspectives.`
        }], "claude-sonnet-4-20250514", 150);

        setEmergentThought(synthesis || "The truth emerges in the space between imagination and analysis.");
        break;
      }

      // Step 2: Execute mode
      let modeResponse = "";
      let modeTurn = {};

      if (decision.nextMode === 'creative') {
        setCreative(prev => ({ ...prev, currentThought: "Generating creative insight..." }));
        modeResponse = await callCreativeMode(userInput, decision.instruction, conversationContext);

        if (modeResponse) {
          modeTurn = {
            mode: 'creative',
            text: modeResponse,
            alpha: creative.alpha
          };

          setCreative(prev => ({ ...prev, currentThought: modeResponse }));

          // Creative response affects Analytical
          const impact = calculateFeedbackImpact('creative', 'analytical', modeResponse);
          applyFeedback('analytical', impact);

          // Add feedback loop
          setFeedbackLoops(prev => [...prev, {
            from: 'creative',
            to: 'analytical',
            message: modeResponse.length > 100 ? "That needs grounding" : "Interesting angle"
          }]);
        }

      } else if (decision.nextMode === 'analytical') {
        setAnalytical(prev => ({ ...prev, currentThought: "Applying critical analysis..." }));
        modeResponse = await callAnalyticalMode(userInput, decision.instruction, conversationContext);

        if (modeResponse) {
          modeTurn = {
            mode: 'analytical',
            text: modeResponse,
            alpha: analytical.alpha
          };

          setAnalytical(prev => ({ ...prev, currentThought: modeResponse }));

          // Analytical response affects Creative
          const impact = calculateFeedbackImpact('analytical', 'creative', modeResponse);
          applyFeedback('creative', impact);

          // Add feedback loop
          setFeedbackLoops(prev => [...prev, {
            from: 'analytical',
            to: 'creative',
            message: modeResponse.includes('but') ? "Your logic limits possibility" : "Fair point"
          }]);
        }
      }

      if (modeResponse) {
        localConversation.push(modeTurn);
        setConversation(prev => [...prev, modeTurn]);

        // Both responses affect Orchestrator
        const orchestratorImpact = calculateFeedbackImpact(
          modeTurn.mode, 
          'orchestrator', 
          modeResponse
        );
        applyFeedback('orchestrator', orchestratorImpact);
      }

      // Update global virtues based on system states
      setGlobalVirtues(prev => ({
        ...prev,
        temperance: (orchestrator.alpha + creative.alpha + analytical.alpha) / 3,
        resolution: Math.max(prev.resolution, orchestrator.emotions.insightful),
        humility: Math.min(1, prev.humility + (analytical.virtues.skepticism - creative.virtues.confidence) * 0.05),
        tranquility: 1 - orchestrator.emotions.impatient
      }));

      // Track alpha history
      setAlphaHistory(prev => ({
        orchestrator: [...prev.orchestrator, orchestrator.alpha],
        creative: [...prev.creative, creative.alpha],
        analytical: [...prev.analytical, analytical.alpha]
      }));

      turn++;
      setCurrentTurn(turn);

      // Add delay for visual effect
      await new Promise(resolve => setTimeout(resolve, 1000));
    }

    // If no synthesis was reached, generate one
    if (!emergentThought && localConversation.length > 2) {
      const finalContext = localConversation.map(t => `${t.mode}: ${t.text}`).join('\n');
      const synthesis = await callClaude([{
        role: "user",
        content: `Synthesize this dialogue into a single emergent insight:
        ${finalContext}`
      }], "claude-sonnet-4-20250514", 100);

      setEmergentThought(synthesis || "The dialogue continues...");
    }

    setIsProcessing(false);
  };

  // === UI COMPONENTS ===

  // System Card Component
  const SystemCard = ({ title, icon: Icon, system, color, position }) => {
    const getEmotionEmoji = (key) => {
      const emojis = {
        curious: '🤔', impatient: '😤', insightful: '💡', patient: '⏳',
        confident: '💪', wild: '🌪️', skeptical: '🤨', precise: '🎯',
        confidence: '💪', momentum: '🏃', wildness: '🌪️', coherence: '🎯',
        skepticism: '🤨', precision: '📐', openness: '🌈', rigor: '⚖️'
      };
      return emojis[key] || '🧠';
    };

    const getColorClass = (color) => {
      const colors = {
        purple: 'bg-purple-500',
        blue: 'bg-blue-500',
        pink: 'bg-pink-500'
      };
      return colors[color] || 'bg-gray-500';
    };

    return (
      <div className={`bg-white/10 backdrop-blur-md rounded-2xl p-6 ${
        position === 'top' ? 'w-96' : 'w-80'
      } border border-white/20 transform transition-all duration-300 hover:scale-105`}>
        {/* Header */}
        <div className="flex items-center mb-4">
          <div className={`w-12 h-12 ${getColorClass(color)} rounded-full flex items-center justify-center`}>
            <Icon className="w-6 h-6 text-white" />
          </div>
          <div className="ml-3">
            <h2 className="text-white font-bold">{title}</h2>
            <p className="text-purple-200 text-sm">
              {position === 'top' ? 'The Shepherd' : `System ${position === 'left' ? '1' : '2'}`}
            </p>
          </div>
        </div>

        {/* Internal Alpha Balance */}
        <div className="mb-4">
          <div className="flex justify-between text-xs text-purple-200 mb-1">
            <span>{position === 'left' ? 'Restrained' : position === 'right' ? 'Rigid' : 'Control'}</span>
            <span className="font-mono">α = {system.alpha.toFixed(2)}</span>
            <span>{position === 'left' ? 'Wild' : position === 'right' ? 'Open' : 'Flow'}</span>
          </div>
          <div className="h-3 bg-black/30 rounded-full relative">
            <div 
              className="absolute top-1/2 -translate-y-1/2 w-5 h-5 bg-white rounded-full shadow-lg border-2 border-purple-400 transition-all duration-500"
              style={{ left: `${system.alpha * 100}%` }}
            />
          </div>
        </div>

        {/* Emotions/Virtues */}
        <div className="grid grid-cols-2 gap-2 mb-4">
          {Object.entries(system.emotions || system.virtues).slice(0, 4).map(([key, value]) => (
            <div key={key} className="bg-black/30 rounded-lg p-2">
              <div className="flex items-center justify-between">
                <span className="text-xs text-white/70 capitalize">{key}</span>
                <span className="text-lg">{getEmotionEmoji(key)}</span>
              </div>
              <div className="h-1 bg-gray-600 rounded-full mt-1">
                <div 
                  className={`h-full ${getColorClass(color)} rounded-full transition-all duration-300`}
                  style={{ width: `${value * 100}%` }}
                />
              </div>
            </div>
          ))}
        </div>

        {/* Current Thought */}
        <div className="bg-purple-500/20 rounded-lg p-3 border border-purple-400/30">
          <p className="text-xs text-white/70 mb-1">Current Thought:</p>
          <p className="text-white text-sm italic line-clamp-3">
            {system.currentThought || "Waiting..."}
          </p>
        </div>
      </div>
    );
  };

  // Benjamin Franklin Virtues Display
  const VirtueEngine = () => {
    return (
      <div className="bg-white/5 backdrop-blur-md rounded-2xl p-6 border border-white/10">
        <h3 className="text-white font-bold mb-4 text-center">
          Benjamin Franklin Virtue Engine
        </h3>
        <div className="grid grid-cols-7 gap-3">
          {Object.entries(globalVirtues).map(([virtue, level]) => (
            <div key={virtue} className="text-center">
              <p className="text-xs text-white/70 mb-2 capitalize">{virtue}</p>
              <div className="h-20 w-8 mx-auto bg-black/30 rounded-full relative overflow-hidden">
                <div 
                  className="absolute bottom-0 w-full bg-gradient-to-t from-purple-500 to-purple-300 rounded-full transition-all duration-500"
                  style={{ height: `${level * 100}%` }}
                />
              </div>
              <p className="text-xs text-white/50 mt-1">{(level * 100).toFixed(0)}%</p>
            </div>
          ))}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 to-purple-900 p-8">
      {/* Title */}
      <div className="text-center mb-8">
        <h1 className="text-3xl font-bold text-white mb-2">
          Cognitive Feedback Engine
        </h1>
        <p className="text-purple-200">Real AI with Recursive State Evolution</p>
      </div>

      {/* Main Container */}
      <div className="max-w-7xl mx-auto">
        {/* Input Section */}
        <div className="mb-8 flex justify-center">
          <div className="bg-white/10 backdrop-blur-md rounded-xl p-4 w-full max-w-2xl">
            <div className="flex gap-2">
              <input
                type="text"
                value={userInput}
                onChange={(e) => setUserInput(e.target.value)}
                placeholder="Enter a thought to process..."
                className="flex-1 bg-black/30 text-white rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-purple-500"
                disabled={isProcessing}
              />
              <button
                onClick={processThought}
                disabled={isProcessing || !userInput}
                className="bg-gradient-to-r from-purple-500 to-blue-500 text-white px-6 py-2 rounded-lg font-semibold disabled:opacity-50 transition-all hover:scale-105"
              >
                {isProcessing ? (
                  <div className="flex items-center">
                    <Brain className="w-5 h-5 mr-2 animate-pulse" />
                    Processing...
                  </div>
                ) : (
                  <div className="flex items-center">
                    <Play className="w-5 h-5 mr-2" />
                    Think
                  </div>
                )}
              </button>
            </div>
            {isProcessing && (
              <div className="mt-2 text-xs text-purple-300 text-center">
                Turn {currentTurn} of {maxTurns}
              </div>
            )}
          </div>
        </div>

        {/* Three Systems Layout */}
        <div className="space-y-8">
          {/* Orchestrator */}
          <div className="flex justify-center">
            <SystemCard
              title="ORCHESTRATOR"
              icon={Brain}
              system={orchestrator}
              color="purple"
              position="top"
            />
          </div>

          {/* Feedback Arrows Animation */}
          {feedbackLoops.length > 0 && (
            <div className="flex justify-center">
              <div className="relative w-96 h-12">
                <svg className="w-full h-full">
                  <path
                    d="M 50 10 Q 200 30 350 10"
                    stroke="#8b5cf6"
                    strokeWidth="2"
                    fill="none"
                    className="animate-pulse"
                  />
                  <path
                    d="M 350 40 Q 200 20 50 40"
                    stroke="#3b82f6"
                    strokeWidth="2"
                    fill="none"
                    className="animate-pulse"
                    style={{ animationDelay: '0.5s' }}
                  />
                </svg>
              </div>
            </div>
          )}

          {/* Creative and Analytical */}
          <div className="flex justify-center gap-8">
            <SystemCard
              title="CREATIVE MODE"
              icon={Sparkles}
              system={creative}
              color="purple"
              position="left"
            />
            <SystemCard
              title="ANALYTICAL MODE"
              icon={Calculator}
              system={analytical}
              color="blue"
              position="right"
            />
          </div>
        </div>

        {/* Benjamin Franklin Virtues */}
        <div className="mt-8">
          <VirtueEngine />
        </div>

        {/* Emergent Synthesis */}
        {emergentThought && (
          <div className="mt-8">
            <div className="bg-gradient-to-r from-purple-500/20 to-blue-500/20 rounded-2xl p-6 backdrop-blur-md border border-white/20">
              <h3 className="text-white font-bold mb-4 text-center">
                Emergent Synthesis
              </h3>
              <p className="text-white/90 italic text-center text-lg">
                "{emergentThought}"
              </p>
              <div className="mt-4 flex justify-center gap-4">
                <span className="text-sm text-purple-300">
                  Creative: {(creative.alpha * 100).toFixed(0)}%
                </span>
                <span className="text-sm text-white/50">|</span>
                <span className="text-sm text-blue-300">
                  Analytical: {(analytical.alpha * 100).toFixed(0)}%
                </span>
                <span className="text-sm text-white/50">|</span>
                <span className="text-sm text-green-300">
                  Coherence: {((orchestrator.emotions.insightful + globalVirtues.resolution) * 50).toFixed(0)}%
                </span>
              </div>
            </div>
          </div>
        )}

        {/* Conversation History */}
        {conversation.length > 0 && (
          <div className="mt-8 bg-black/30 rounded-xl p-4">
            <h3 className="text-white font-bold mb-3">Thought Stream</h3>
            <div className="space-y-2 max-h-96 overflow-y-auto">
              {conversation.map((turn, idx) => (
                <div 
                  key={idx}
                  className={`p-3 rounded-lg bg-gradient-to-r ${
                    turn.mode === 'orchestrator' ? 'from-purple-500/20 to-purple-600/20' :
                    turn.mode === 'creative' ? 'from-pink-500/20 to-purple-500/20' :
                    'from-blue-500/20 to-cyan-500/20'
                  }`}
                >
                  <div className="flex items-center justify-between mb-1">
                    <span className="text-white/70 text-sm font-semibold capitalize">
                      {turn.mode}
                    </span>
                    <span className="text-white/50 text-xs font-mono">
                      α={turn.alpha.toFixed(2)}
                    </span>
                  </div>
                  <p className="text-white/90 text-sm">{turn.text}</p>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Feedback Loops Display */}
        {feedbackLoops.length > 0 && (
          <div className="mt-4 bg-black/20 rounded-lg p-3">
            <h4 className="text-white/70 text-xs font-semibold mb-2">Feedback Loops</h4>
            <div className="flex flex-wrap gap-2">
              {feedbackLoops.slice(-5).map((loop, idx) => (
                <span key={idx} className="text-xs bg-white/10 rounded px-2 py-1 text-white/60">
                  {loop.from} → {loop.to}: "{loop.message}"
                </span>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default CognitiveFeedbackEngine;

